namespace RecipeShare.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

public class RecipeSubmission
{
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
}

using RecipeShare.Models;

namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes = new()
    {
        new Recipe { Id = 1, Title = "Classic Margherita Pizza", Category = "Italian", Ingredients = "Pizza dough, San Marzano tomatoes, Fresh mozzarella, Basil, Olive oil", Steps = "1. Preheat oven to 475°F\n2. Roll out dough\n3. Spread crushed tomatoes\n4. Add torn mozzarella\n5. Bake 10-12 minutes\n6. Top with fresh basil", AverageRating = 4.5, RatingCount = 12 },
        new Recipe { Id = 2, Title = "Chicken Tikka Masala", Category = "Indian", Ingredients = "Chicken thighs, Yogurt, Garam masala, Tomato sauce, Heavy cream, Onion, Garlic, Ginger", Steps = "1. Marinate chicken in yogurt and spices\n2. Grill or broil chicken\n3. Sauté onions, garlic, ginger\n4. Add tomato sauce and cream\n5. Simmer with chicken pieces", AverageRating = 4.8, RatingCount = 20 },
        new Recipe { Id = 3, Title = "Beef Tacos", Category = "Mexican", Ingredients = "Ground beef, Taco shells, Lettuce, Tomato, Cheese, Sour cream, Taco seasoning", Steps = "1. Brown ground beef\n2. Add taco seasoning and water\n3. Simmer until thickened\n4. Warm taco shells\n5. Assemble with toppings", AverageRating = 4.2, RatingCount = 8 },
        new Recipe { Id = 4, Title = "Pad Thai", Category = "Asian", Ingredients = "Rice noodles, Shrimp, Eggs, Bean sprouts, Peanuts, Lime, Fish sauce, Tamarind paste", Steps = "1. Soak rice noodles\n2. Stir-fry shrimp\n3. Scramble eggs in wok\n4. Add noodles and sauce\n5. Toss with bean sprouts\n6. Garnish with peanuts and lime", AverageRating = 4.6, RatingCount = 15 },
        new Recipe { Id = 5, Title = "Chocolate Lava Cake", Category = "Desserts", Ingredients = "Dark chocolate, Butter, Eggs, Sugar, Flour", Steps = "1. Melt chocolate and butter\n2. Whisk eggs and sugar\n3. Fold in flour and chocolate mixture\n4. Pour into greased ramekins\n5. Bake at 425°F for 12 minutes\n6. Invert onto plate immediately", AverageRating = 4.9, RatingCount = 25 },
        new Recipe { Id = 6, Title = "Caesar Salad", Category = "Salads", Ingredients = "Romaine lettuce, Parmesan, Croutons, Caesar dressing, Lemon, Anchovies", Steps = "1. Wash and chop romaine\n2. Make dressing with anchovies, lemon, garlic\n3. Toss lettuce with dressing\n4. Top with croutons and shaved Parmesan", AverageRating = 4.0, RatingCount = 6 },
        new Recipe { Id = 7, Title = "Spaghetti Carbonara", Category = "Italian", Ingredients = "Spaghetti, Guanciale, Eggs, Pecorino Romano, Black pepper", Steps = "1. Cook pasta al dente\n2. Crisp guanciale in pan\n3. Mix eggs with grated pecorino\n4. Toss hot pasta with guanciale\n5. Remove from heat, stir in egg mixture\n6. Season with black pepper", AverageRating = 4.7, RatingCount = 18 },
        new Recipe { Id = 8, Title = "Guacamole", Category = "Mexican", Ingredients = "Avocados, Lime juice, Cilantro, Red onion, Jalapeño, Tomato, Salt", Steps = "1. Halve and pit avocados\n2. Mash to desired consistency\n3. Mix in lime juice and salt\n4. Fold in diced onion, tomato, jalapeño\n5. Garnish with cilantro", AverageRating = 4.4, RatingCount = 10 },
    };

    private readonly Lock _lock = new();

    public IReadOnlyList<string> GetCategories()
    {
        lock (_lock)
        {
            return _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();
        }
    }

    public IReadOnlyList<Recipe> GetRecipesByCategory(string category)
    {
        lock (_lock)
        {
            return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
        }
    }

    public Recipe? GetRecipeById(int id)
    {
        lock (_lock)
        {
            return _recipes.FirstOrDefault(r => r.Id == id);
        }
    }

    public void AddRating(int recipeId, int stars)
    {
        lock (_lock)
        {
            var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
            if (recipe is not null && stars >= 1 && stars <= 5)
            {
                var totalStars = recipe.AverageRating * recipe.RatingCount + stars;
                recipe.RatingCount++;
                recipe.AverageRating = Math.Round(totalStars / recipe.RatingCount, 1);
            }
        }
    }

    public void SubmitRecipe(RecipeSubmission submission)
    {
        lock (_lock)
        {
            var newId = _recipes.Max(r => r.Id) + 1;
            _recipes.Add(new Recipe
            {
                Id = newId,
                Title = submission.Title,
                Category = submission.Category,
                Ingredients = submission.Ingredients,
                Steps = submission.Steps,
                AverageRating = 0,
                RatingCount = 0
            });
        }
    }
}

