@page "/category/{CategoryName}"
@using RecipeShare.Services
@using RecipeShare.Models
@inject RecipeService RecipeService

<PageTitle>@CategoryName Recipes - RecipeShare</PageTitle>

<h1>@CategoryName Recipes</h1>
<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

@if (Recipes.Count == 0)
{
    <p>No recipes found in this category.</p>
}
else
{
    <div class="row">
        @foreach (var recipe in Recipes)
        {
            <div class="col-md-6 mb-3">
                <div class="card">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text">
                            <span class="text-warning">@(new string('★', (int)Math.Round(recipe.AverageRating)))@(new string('☆', 5 - (int)Math.Round(recipe.AverageRating)))</span>
                            <small class="text-muted">(@recipe.AverageRating / 5, @recipe.RatingCount ratings)</small>
                        </p>
                        <a href="/recipe/@recipe.Id" class="btn btn-outline-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter]
    public string CategoryName { get; set; } = string.Empty;

    private IReadOnlyList<Recipe> Recipes { get; set; } = [];

    protected override void OnParametersSet()
    {
        Recipes = RecipeService.GetRecipesByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"
@using RecipeShare.Services
@using RecipeShare.Models
@inject RecipeService RecipeService

<PageTitle>@(Recipe?.Title ?? "Recipe") - RecipeShare</PageTitle>

@if (Recipe is null)
{
    <h1>Recipe Not Found</h1>
    <p>Sorry, we couldn't find that recipe.</p>
    <a href="/">Back to Home</a>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="/category/@Recipe.Category">@Recipe.Category</a></li>
            <li class="breadcrumb-item active">@Recipe.Title</li>
        </ol>
    </nav>

    <h1>@Recipe.Title</h1>
    <p><span class="badge bg-secondary">@Recipe.Category</span></p>

    <h3>Ingredients</h3>
    <ul>
        @foreach (var ingredient in Recipe.Ingredients.Split(',', StringSplitOptions.TrimEntries))
        {
            <li>@ingredient</li>
        }
    </ul>

    <h3>Steps</h3>
    <ol>
        @foreach (var step in Recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            var text = step.TrimStart();
            if (text.Length > 2 && text[1] == '.' && char.IsDigit(text[0]))
                text = text[3..];
            else if (text.Length > 3 && text[2] == '.' && char.IsDigit(text[0]) && char.IsDigit(text[1]))
                text = text[4..];
            <li>@text.Trim()</li>
        }
    </ol>

    <h3>Rating</h3>
    <p>
        <span class="text-warning">@(new string('★', (int)Math.Round(Recipe.AverageRating)))@(new string('☆', 5 - (int)Math.Round(Recipe.AverageRating)))</span>
        <span class="text-muted">@Recipe.AverageRating / 5 (@Recipe.RatingCount ratings)</span>
    </p>

    <StarRating RecipeId="Recipe.Id" />
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Recipe? Recipe { get; set; }

    protected override void OnParametersSet()
    {
        Recipe = RecipeService.GetRecipeById(Id);
    }
}

@rendermode InteractiveServer
@using RecipeShare.Services
@inject RecipeService RecipeService

<div class="my-3 p-3 border rounded">
    <h5>Rate this recipe</h5>
    @if (Submitted)
    {
        <p class="text-success">Thanks for your rating of @SelectedRating star(s)!</p>
    }
    else
    {
        <div style="font-size: 2rem; cursor: pointer;">
            @for (int i = 1; i <= 5; i++)
            {
                var star = i;
                <span @onclick="() => SubmitRating(star)"
                      @onmouseover="() => HoverRating = star"
                      @onmouseout="() => HoverRating = 0"
                      class="@(star <= DisplayRating ? "text-warning" : "text-muted")">★</span>
            }
        </div>
        <small class="text-muted">Click a star to rate</small>
    }
</div>

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private int HoverRating { get; set; }
    private int SelectedRating { get; set; }
    private bool Submitted { get; set; }

    private int DisplayRating => HoverRating > 0 ? HoverRating : SelectedRating;

    private void SubmitRating(int stars)
    {
        SelectedRating = stars;
        RecipeService.AddRating(RecipeId, stars);
        Submitted = true;
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeShare.Services
@using RecipeShare.Models
@inject RecipeService RecipeService

<PageTitle>Submit Recipe - RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (SubmitSuccess)
{
    <div class="alert alert-success">
        <strong>Recipe submitted!</strong> Your recipe "@Submission.Title" has been added.
        <a href="/">Browse recipes</a>
    </div>
}
else
{
    <EditForm Model="Submission" OnValidSubmit="HandleSubmit" FormName="recipe-form">
        <DataAnnotationsValidator />
        <ValidationSummary />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" @bind-Value="Submission.Title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" @bind-Value="Submission.Category" class="form-select">
                <option value="">-- Select a category --</option>
                @foreach (var cat in RecipeService.GetCategories())
                {
                    <option value="@cat">@cat</option>
                }
                <option value="Other">Other</option>
            </InputSelect>
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients</label>
            <InputTextArea id="ingredients" @bind-Value="Submission.Ingredients" class="form-control" rows="4" placeholder="List ingredients separated by commas" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps</label>
            <InputTextArea id="steps" @bind-Value="Submission.Steps" class="form-control" rows="6" placeholder="Describe each step on a new line" />
        </div>

        <button type="submit" class="btn btn-success" disabled="@(!IsFormValid)">Submit Recipe</button>
    </EditForm>
}

@code {
    private RecipeSubmission Submission { get; set; } = new();
    private bool SubmitSuccess { get; set; }

    private bool IsFormValid =>
        !string.IsNullOrWhiteSpace(Submission.Title) &&
        !string.IsNullOrWhiteSpace(Submission.Category) &&
        !string.IsNullOrWhiteSpace(Submission.Ingredients) &&
        !string.IsNullOrWhiteSpace(Submission.Steps);

    private void HandleSubmit()
    {
        if (IsFormValid)
        {
            RecipeService.SubmitRecipe(Submission);
            SubmitSuccess = true;
        }
    }
}

